package org.apache.commons.csv;

import static org.junit.jupiter.api.Assertions.*;
import org.apache.commons.csv.CSVFormat;
import org.junit.jupiter.api.Test;

class CSVFormatTest {

    @Test
    void testWithTrim() {
        CSVFormat format = CSVFormat.DEFAULT;
        CSVFormat trimmedFormat = format.withTrim();

        assertNotNull(trimmedFormat);
        assertTrue(trimmedFormat.getTrim());
        // original format should remain unchanged (immutable)
        assertFalse(format.getTrim());

        // verify that withTrim(true) returns an instance with trim = true
        CSVFormat explicitTrimTrue = format.withTrim(true);
        assertTrue(explicitTrimTrue.getTrim());

        // verify that withTrim(false) returns an instance with trim = false
        CSVFormat explicitTrimFalse = format.withTrim(false);
        assertFalse(explicitTrimFalse.getTrim());

        // chaining withTrim(true) after withTrim(false)
        CSVFormat chainTrim = explicitTrimFalse.withTrim(true);
        assertTrue(chainTrim.getTrim());
    }
}
